mapper.select:
SELECT host.name hostName, DEV_NAME as devName, TIME as time, HOST_ID as hostId, IO_STAT as ioStat, RD_STAT as rdStat, WR_STAT as wrStat, RD_REQ_PS AS rdReqps, WR_REQ_PS AS wrReqps, RD_LATENCY as rdLatency, WR_LATENCY as wrLatency, UTILIZATION as utilization, fs.title as title FROM TBL_HOST_IO_STAT t LEFT JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_SHARE_FILE_SYSTEM} fs on fs.name = t.DEV_NAME RIGHT JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_HOST} host ON t.HOST_ID = host.id WHERE TIME BETWEEN ${startTime} AND ${endTime}
AND t.HOST_ID IN (${hostIds})
AND t.CLUSTER_ID =${clusterId}
AND t.DEV_NAME = #{currentDisk}
AND t.DEV_NAME in (select storage_pool_name from ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_STORAGE_POOL_CONFIG} con WHERE con.type in(1,2,9,10))
ORDER BY TIME ASC

SELECT DEV_NAME as devName,


        RD_STAT as rdStat, WR_STAT as wrStat, RD_REQ_PS AS rdReqps, WR_REQ_PS AS wrReqps, RD_LATENCY as rdLatency, WR_LATENCY as wrLatency


        SUM(RD_STAT) as rdStat, SUM(WR_STAT) as wrStat, SUM(RD_REQ_PS) AS rdReqps, SUM(WR_REQ_PS) AS wrReqps


FROM TBL_HOST_IO_STAT t  WHERE 1=1

    AND HOST_ID =${hostId}


    AND CLUSTER_ID =${clusterId}

AND TIME BETWEEN ${startTime} AND ${endTime}
AND t.DEV_NAME in (select storage_pool_name from ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_STORAGE_POOL_CONFIG} con WHERE con.type in(1,2,9,10))

    AND DEV_NAME =#{currentDisk}


    GROUP BY DEV_NAME


    ORDER BY TIME ASC

SELECT  MAX(tdio.UTILIZATION) as utilization,  tdio.HOST_ID as hostId from TBL_HOST_IO_STAT tdio
WHERE tdio.TIME=(SELECT MAX(TIME) FROM TBL_HOST_IO_STAT)-${duration}

    AND tdio.HOST_POOL_ID= ${hostPoolId}


    AND tdio.CLUSTER_ID= ${clusterId}


    AND tdio.OP_GROUP_CODE LIKE #{operatorGroupCode}

GROUP BY tdio.HOST_ID

SELECT DEV_NAME as devName,


        RD_STAT as rdStat, WR_STAT as wrStat, round(RD_REQ/30) AS rdReq, round(WR_REQ/30) AS wrReq, RD_LATENCY as rdLatency, WR_LATENCY as wrLatency,HOST_ID as hostId,CLUSTER_ID as clusterId


        SUM(RD_STAT) as rdStat, SUM(WR_STAT) as wrStat, round(SUM(RD_REQ/30)) AS rdReq, round(SUM(WR_REQ/30)) AS wrReq,any(HOST_ID) as hostId, any(CLUSTER_ID) as clusterId


FROM TBL_HOST_IO_STAT  t  WHERE 1=1

    AND HOST_ID =${hostId}


    AND CLUSTER_ID =${clusterId}

AND TIME BETWEEN ${startTime} AND ${endTime}
AND DEV_NAME in (select storage_pool_name from ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_STORAGE_POOL_CONFIG} con WHERE con.type in(1,2,9,10))

    GROUP BY DEV_NAME


    ORDER BY TIME ASC

SELECT tdio.HOST_ID hostId,SUM(tdio.IO_STAT) as ioStat, tdio.TIME as time, TT.name as hostName
FROM TBL_HOST_IO_STAT tdio  INNER JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_HOST} TT ON tdio.HOST_ID=TT.id WHERE tdio.HOST_ID in (${hostIds})

    AND tdio.OP_GROUP_CODE LIKE #{operatorGroupCode}

AND tdio.TIME BETWEEN ${startTime} AND ${endTime}
GROUP BY tdio.HOST_ID, tdio.TIME, TT.name ORDER BY tdio.TIME ASC

SELECT  tdio.DEV_NAME devName,SUM(tdio.IO_STAT) as ioStat, tdio.TIME as time
FROM TBL_HOST_IO_STAT tdio  WHERE tdio.DEV_NAME IN (${devNames})

    AND tdio.OP_GROUP_CODE LIKE #{operatorGroupCode}

AND tdio.TIME BETWEEN ${startTime} AND ${endTime}
GROUP BY tdio.DEV_NAME, tdio.TIME ORDER BY tdio.TIME ASC

SELECT tdio.HOST_ID hostId, RD_REQ_PS AS rdReqps, WR_REQ_PS AS wrReqps, tdio.RD_LATENCY as rdLatency, tdio.WR_LATENCY as wrLatency, tdio.TIME as time, TT.name as hostName
FROM TBL_HOST_IO_STAT tdio
INNER JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_HOST} TT ON tdio.HOST_ID=TT.id
WHERE tdio.HOST_ID=${hostId}

    AND tdio.DEV_NAME =#{currentDisk}


    AND tdio.OP_GROUP_CODE LIKE #{operatorGroupCode}

AND tdio.TIME BETWEEN ${startTime} AND ${endTime}
ORDER BY tdio.TIME ASC

SELECT DISTINCT tdio.DEV_NAME devName, SUM(RD_REQ_PS)AS rdReqps, SUM(WR_REQ_PS) AS wrReqps, tdio.TIME as time
FROM TBL_HOST_IO_STAT tdio   WHERE tdio.DEV_NAME IN (${devNames})

    AND tdio.OP_GROUP_CODE LIKE #{operatorGroupCode}

AND tdio.TIME BETWEEN ${startTime} AND ${endTime}
GROUP BY tdio.DEV_NAME, tdio.TIME ORDER BY tdio.TIME ASC

SELECT his.HOST_ID hostId,SUM(his.rd_ps_avg) + SUM(his.wr_ps_avg) reqps, th.name hostName, any(th.cluster_id) clusterId, any(th.host_pool_id) hostpoolId
FROM (SELECT HOST_ID, CEILING(AVG(RD_REQ_PS)) rd_ps_avg, CEILING(AVG(WR_REQ_PS)) wr_ps_avg FROM TBL_HOST_IO_STAT where
TIME BETWEEN ${startTime} AND ${endTime}

    AND HOST_POOL_ID =${hostPoolId}


    AND  HOST_ID =${hostId}


    AND CLUSTER_ID =${clusterId}


    AND OP_GROUP_CODE LIKE #{operatorGroupCode}

GROUP BY HOST_ID, DEV_NAME HAVING MAX(TIME) > ${endTime} - 241) as his,
${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_HOST} th WHERE th.id = his.HOST_ID
GROUP BY his.HOST_ID, th.name
ORDER BY reqps DESC

    LIMIT ${limit}

SELECT t2.DEV_NAME as devName,round(SUM(t2.RD_REQ_PS+ t2.WR_REQ_PS)) as reqps,t2.TIME as time, any(t1.TITLE) as title FROM
( SELECT SUM(RD_REQ_PS+WR_REQ_PS) SUM_REQ_PS,DEV_NAME,any(FS.title) as TITLE  FROM TBL_HOST_IO_STAT t
LEFT JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_SHARE_FILE_SYSTEM} FS on FS.name=t.DEV_NAME
WHERE TIME BETWEEN ${startTime} AND ${endTime}
AND DEV_NAME in (select storage_pool_name from ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_STORAGE_POOL_CONFIG} con WHERE con.type in(1,2,9,10))

    AND t.OP_GROUP_CODE LIKE #{operatorGroupCode}

GROUP BY DEV_NAME ORDER BY SUM_REQ_PS DESC

    LIMIT ${limit}

) t1  LEFT JOIN TBL_HOST_IO_STAT  t2 ON t1.DEV_NAME=t2.DEV_NAME  WHERE TIME BETWEEN ${startTime} AND ${endTime}
GROUP BY t2.DEV_NAME,t2.TIME ORDER BY TIME ASC

SELECT tis.RD_REQ_PS+tis.WR_REQ_PS as reqps,tis.TIME as time, t.clusterName as clusterName FROM (SELECT SUM(th.RD_REQ+th.WR_REQ) total,th.CLUSTER_ID clusterId, any(c.name) clusterName,any(th.DEV_NAME) devName FROM TBL_HOST_IO_STAT th INNER JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_CLUSTER} c ON th.CLUSTER_ID = c.id WHERE th.TIME BETWEEN ${startTime} AND ${endTime}
AND th.OP_GROUP_CODE LIKE #{operatorGroupCode}
GROUP BY th.CLUSTER_ID ORDER BY total DESC LIMIT ${limit}) t LEFT JOIN TBL_HOST_IO_STAT tis ON tis.CLUSTER_ID = t.clusterId LEFT JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_SHARE_FILE_SYSTEM} fs ON fs.name = t.devName WHERE tis.TIME BETWEEN ${startTime} AND ${endTime} AND tis.DEV_NAME in (select storage_pool_name from ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_STORAGE_POOL_CONFIG} con WHERE con.type in(1,2,9,10)) ORDER BY t.clusterName, tis.TIME

SELECT tis.IO_STAT ioStat, tis.TIME as time, t.clusterName as clusterName FROM (SELECT any(th.TIME) time, SUM(th.IO_STAT) total, any(c.name) clusterName,th.CLUSTER_ID clusterId,any(th.DEV_NAME) devName FROM TBL_HOST_IO_STAT th INNER JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_CLUSTER} c ON th.CLUSTER_ID = c.id WHERE TIME BETWEEN ${startTime} AND ${endTime}
AND th.OP_GROUP_CODE LIKE #{operatorGroupCode}
GROUP BY th.CLUSTER_ID ORDER BY total DESC LIMIT ${limit}) t LEFT JOIN TBL_HOST_IO_STAT tis ON tis.CLUSTER_ID = t.clusterId LEFT JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_SHARE_FILE_SYSTEM} fs ON fs.name = t.devName WHERE tis.TIME BETWEEN ${startTime} AND ${endTime} AND tis.DEV_NAME in (select storage_pool_name from ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_STORAGE_POOL_CONFIG} con WHERE con.type in(1,2,9,10)) ORDER BY t.clusterName,tis.TIME

SELECT t2.DEV_NAME as devName,round(SUM(t2.RD_LATENCY+t2.WR_LATENCY),2) as latency,t2.TIME as time,any(t1.TITLE) as title FROM
( SELECT SUM(RD_LATENCY+WR_LATENCY) SUM_LATENCY,DEV_NAME, any(FS.title) as TITLE FROM TBL_HOST_IO_STAT t
LEFT JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_SHARE_FILE_SYSTEM} FS on FS.name=t.DEV_NAME
WHERE TIME BETWEEN ${startTime} AND ${endTime}
AND DEV_NAME in (select storage_pool_name from ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_STORAGE_POOL_CONFIG} con WHERE con.type in(1,2,9,10))

    AND OP_GROUP_CODE LIKE #{operatorGroupCode}

GROUP BY DEV_NAME ORDER BY SUM_LATENCY DESC

    LIMIT ${limit}

) t1 LEFT JOIN TBL_HOST_IO_STAT  t2 ON t1.DEV_NAME=t2.DEV_NAME WHERE TIME BETWEEN ${startTime} AND ${endTime}
GROUP BY t2.DEV_NAME,t2.TIME ORDER BY t2.TIME ASC
